import{c as i,S as n,j as l,m as a}from"./chunks/framework.DvQr6YbT.js";const u=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/index.md","filePath":"troubleshooting/index.md","lastUpdated":1783065655000}'),o={name:"troubleshooting/index.md"};function s(t,e,r,d,h,c){return n(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “Troubleshooting”">​</a></h1><p>Use this page when setup, skills, platform config, or vault health does not look right.</p><h2 id="the-dashboard-says-the-vault-is-not-set-up" tabindex="-1">The Dashboard Says the Vault Is Not Set Up <a class="header-anchor" href="#the-dashboard-says-the-vault-is-not-set-up" aria-label="Permalink to “The Dashboard Says the Vault Is Not Set Up”">​</a></h2><p>Knowlery checks for <code>.knowlery/manifest.json</code> or <code>KNOWLEDGE.md</code>.</p><p>If the vault should already be initialized:</p><ol><li>Confirm <code>.knowlery/manifest.json</code> or <code>KNOWLEDGE.md</code> exists.</li><li>If the manifest exists, confirm it contains valid JSON.</li><li>Reopen the dashboard.</li><li>If it is missing or corrupted, run setup again or use maintenance actions from settings.</li></ol><h2 id="node-js-is-not-detected" tabindex="-1">Node.js Is Not Detected <a class="header-anchor" href="#node-js-is-not-detected" aria-label="Permalink to “Node.js Is Not Detected”">​</a></h2><p>Node.js is required for skill registry browsing and optional tooling preparation.</p><p>Try this:</p><ol><li>Install Node.js from the official Node.js website.</li><li>Restart Obsidian.</li><li>Use the Node.js auto-detect button in Knowlery settings.</li><li>If auto-detect fails, enter the Node.js path manually.</li></ol><p>On macOS and Linux, GUI apps sometimes do not inherit the same shell PATH as your terminal. Manual path entry can be necessary.</p><h2 id="skill-browser-does-not-work" tabindex="-1">Skill Browser Does Not Work <a class="header-anchor" href="#skill-browser-does-not-work" aria-label="Permalink to “Skill Browser Does Not Work”">​</a></h2><p>The skill browser depends on Node.js, npm, and the external skills CLI path used through <code>npx skills</code>.</p><p>Check:</p><ul><li>Node.js is installed and detected.</li><li>npm is available.</li><li>The search term is not empty.</li><li>Network access is available.</li><li>The external skills registry is reachable.</li></ul><p>If the registry cannot be used, built-in and custom skills still work.</p><h2 id="built-in-skills-are-missing" tabindex="-1">Built-In Skills Are Missing <a class="header-anchor" href="#built-in-skills-are-missing" aria-label="Permalink to “Built-In Skills Are Missing”">​</a></h2><p>Open <strong>Settings -&gt; Knowlery</strong>, then check <strong>Skills installed</strong> in Diagnostics.</p><p>Built-in skills are expected at <code>.agents/skills/&lt;name&gt;/SKILL.md</code>.</p><p>If some are missing:</p><ol><li>Re-run setup in a test vault to compare expected output.</li><li>Use the Skills section in settings to re-enable disabled skills when possible.</li><li>Use maintenance actions to re-initialize or repair the vault if the installation is incomplete.</li></ol><h2 id="claude-code-config-is-missing" tabindex="-1">Claude Code Config Is Missing <a class="header-anchor" href="#claude-code-config-is-missing" aria-label="Permalink to “Claude Code Config Is Missing”">​</a></h2><p>For Claude Code, Knowlery expects:</p><ul><li><code>.claude/CLAUDE.md</code></li><li><code>.claude/rules/</code></li><li><code>.agents/skills/</code></li></ul><p>Use settings to regenerate agent config. If you switched from OpenCode, confirm the active platform is Claude Code.</p><h2 id="opencode-config-is-missing" tabindex="-1">OpenCode Config Is Missing <a class="header-anchor" href="#opencode-config-is-missing" aria-label="Permalink to “OpenCode Config Is Missing”">​</a></h2><p>For OpenCode, Knowlery expects:</p><ul><li><code>opencode.json</code></li><li><code>.agents/rules/</code></li><li><code>.agents/skills/</code></li></ul><p>Use settings to regenerate agent config. If you switched from Claude Code, confirm the active platform is OpenCode.</p><h2 id="broken-wikilinks" tabindex="-1">Broken Wikilinks <a class="header-anchor" href="#broken-wikilinks" aria-label="Permalink to “Broken Wikilinks”">​</a></h2><p>Broken wikilinks mean Obsidian cannot resolve a link target.</p><p>Common causes:</p><ul><li>The target note was renamed or deleted.</li><li>The link text has a typo.</li><li>A note exists in a different folder with an unexpected title.</li></ul><p>Fix the link or restore the target note, then run diagnosis again.</p><h2 id="orphan-notes" tabindex="-1">Orphan Notes <a class="header-anchor" href="#orphan-notes" aria-label="Permalink to “Orphan Notes”">​</a></h2><p>Orphan notes have no incoming wikilinks.</p><p>This is not always bad. Daily notes, inbox notes, or temporary notes can be orphaned by design. For knowledge pages, orphans often mean the page has not been connected back into the map.</p><h2 id="missing-frontmatter" tabindex="-1">Missing Frontmatter <a class="header-anchor" href="#missing-frontmatter" aria-label="Permalink to “Missing Frontmatter”">​</a></h2><p>Knowlery checks frontmatter only in the knowledge directories.</p><p>If a file in <code>entities/</code>, <code>concepts/</code>, <code>comparisons/</code>, or <code>queries/</code> has missing frontmatter, compare it with <code>SCHEMA.md</code> and add the missing fields.</p><h2 id="optional-installs-failed" tabindex="-1">Optional Installs Failed <a class="header-anchor" href="#optional-installs-failed" aria-label="Permalink to “Optional Installs Failed”">​</a></h2><p>Optional installs run local commands on your machine.</p><p>If an install fails:</p><ol><li>Check that Node.js is detected when the item requires Node.</li><li>Try the equivalent install command in a terminal.</li><li>Restart Obsidian after installing external tools.</li><li>Reopen setup or settings and re-run detection.</li></ol><h2 id="a-knowledge-bundle-will-not-install" tabindex="-1">A Knowledge Bundle Will Not Install <a class="header-anchor" href="#a-knowledge-bundle-will-not-install" aria-label="Permalink to “A Knowledge Bundle Will Not Install”">​</a></h2><p>Install validates the bundle before writing anything.</p><p>Common causes:</p><ul><li>The <code>.zip</code> or folder does not contain a <code>knowlery-bundle.json</code> manifest at its root.</li><li>The bundle id is path-unsafe, or an entry path tries to escape <code>Library/&lt;bundle-id&gt;/</code>.</li><li>The same bundle is already installed at the same or a newer version — updates require a newer bundle version.</li><li>The bundle has conformance errors — installing past them requires explicit acknowledgement in the install preview.</li></ul><p>Ask the sender to re-export with a current Knowlery version if the manifest or paths look wrong.</p><h2 id="installed-bundle-knowledge-does-not-show-up-in-answers" tabindex="-1">Installed Bundle Knowledge Does Not Show Up in Answers <a class="header-anchor" href="#installed-bundle-knowledge-does-not-show-up-in-answers" aria-label="Permalink to “Installed Bundle Knowledge Does Not Show Up in Answers”">​</a></h2><p>The <code>/ask</code> skill reads <code>.knowlery/bundles.json</code> and each relevant bundle&#39;s <code>agent-index.json</code> under <code>Library/&lt;bundle-id&gt;/</code>.</p><p>Check:</p><ol><li>The bundle appears in the Bundles section on the dashboard.</li><li><code>.knowlery/bundles.json</code> lists the bundle.</li><li><code>KNOWLEDGE.md</code> contains the installed-bundles pointer block.</li><li>The vault&#39;s <code>/ask</code> skill is current — bundled skills refresh automatically when the plugin version changes.</li></ol><h2 id="when-to-file-an-issue" tabindex="-1">When to File an Issue <a class="header-anchor" href="#when-to-file-an-issue" aria-label="Permalink to “When to File an Issue”">​</a></h2><p>Open a GitHub issue when you can reproduce the problem in a clean test vault and can include:</p><ul><li>Knowlery version.</li><li>Obsidian version.</li><li>Operating system.</li><li>Active platform, either Claude Code or OpenCode.</li><li>Steps to reproduce.</li><li>Any relevant console errors.</li></ul>',56)])])}const m=i(o,[["render",s]]);export{u as __pageData,m as default};
